const products = [
  { name: 'Nine-Tailed Fox Pendant', slug: 'nine-tailed-fox-pendant', emoji: '🦊' },
  { name: 'Phoenix Necklace', slug: 'phoenix-rebirth-necklace', emoji: '🔥' },
  { name: 'Azure Dragon Ring', slug: 'azure-dragon-ring', emoji: '🐉' },
  { name: 'White Tiger Cuff', slug: 'white-tiger-guardian-cuff', emoji: '🐅' },
  { name: 'Qilin Bracelet', slug: 'qilin-protection-bracelet', emoji: '✨' },
  { name: 'Black Tortoise Bracelet', slug: 'black-tortoise-endurance-bracelet', emoji: '🐢' },
  { name: '28 Mansions — Jiao', slug: 'jiao-mansion-bracelet', emoji: '⭐' },
];

const d = new Date();
const idx = (d.getDate() - 1) % products.length;
const p = products[idx];
const imageUrl = `https://mythrealms-shop.vercel.app/images/products/${p.slug}.png`;
const caption = `${p.emoji} ${p.name}

Handcrafted in 14k gold and sterling silver.
Inspired by the Classic of Mountains and Seas — China\'s oldest book of legends.

Tap the link in bio to discover your guardian.

#mythicaljewelry #chinesemythology #handcrafted #luxuryjewelry #shanhaijing`;

return [{ json: { caption, imageUrl, productUrl: `https://mythrealms-shop.vercel.app/products/${p.slug}` } }];
